module top_module(
    input clk,
    input load,
    input [3:0] data_in,
    input shift_in,
    output [3:0] data_out,
    output shift_out
);reg [3:0] obf_register;

always @(posedge clk) begin
    if (load) begin
        obf_register <= data_in;
    end else begin
        obf_register <= {shift_in, obf_register[3:1]};
    end
end

assign data_out = obf_register;
assign shift_out = obf_register[3];

endmodule
